
var BINDB = {
	"tex/burlap": "~/img/burlap.webp",
	"tex/brick": "~/img/brick.webp",
	"tex/blocks": "~/img/blocks.webp",
	"tex/canvas": "~/img/canvas.webp",
	"tex/tinylens": "~/img/tinylens.webp",
	"img/beach": "~/img/beach.jpg",
	"wasm/zstd": "~/wasm/zstd.wasm",
	"wasm/webp": "~/wasm/webp.wasm",
	"wasm/jpg": "~/wasm/jpg.wasm",
	"icc/adobe": "~/icc/adobe.icc",
	"icc/prophoto": "~/icc/prophoto.icc",
	"icc/displayp3": "~/icc/displayp3.icc"
};

var BINDB_DATA = {};
await Promise.all(Object.keys(BINDB).map(async key => {
	let res = await window.fetch(BINDB[key], { responseType: "arrayBuffer" });
	BINDB_DATA[key] = new Uint8Array(res.arrayBuffer);
}));


